// 適用
let added = 0;
let skipped = 0;
for (const s of t.sentences) {
  for (const tk of s.tokens) {
    if (hints[tk.id]) {
      if (tk.hint) {
        skipped++;
      } else {
        tk.hint = hints[tk.id];
        added++;
      }
    }
  }
}

// 検証
const tokens = t.sentences.flatMap(s => s.tokens);
const meaningful = tokens.filter(tk => tk.layer > 0 || (tk.grammarTag && tk.grammarTag.pos));
const withHint = meaningful.filter(tk => tk.hint).length;
const coverage = Math.round((withHint / meaningful.length) * 100);

let allOk = true;
for (const s of t.sentences) {
  const concat = s.tokens.map(tk => tk.text).join('');
  if (concat !== s.originalText) {
    console.error(`MISMATCH ${s.id}`);
    allOk = false;
  }
}
if (!allOk) {
  console.error('Validation failed. Not writing.');
  process.exit(1);
}

fs.writeFileSync(fp, JSON.stringify(t, null, 2), 'utf8');
if (fs.existsSync(path.dirname(distFp))) {
  fs.writeFileSync(distFp, JSON.stringify(t, null, 2), 'utf8');
}

console.log(`Added: ${added}, skipped (already has hint): ${skipped}`);
console.log(`Total tokens: ${tokens.length}, meaningful: ${meaningful.length}`);
console.log(`With hint (meaningful): ${withHint} (${coverage}%)`);
console.log(`With hint (all): ${tokens.filter(tk => tk.hint).length}`);
